236 bool ConstantRange::getEquivalentICmp(CmpInst::Predicate &Pred,
237                                       APInt &RHS) const {
238   APInt Offset;
239   getEquivalentICmp(Pred, RHS, Offset);
240   return Offset.isZero();
241 }
